import "./App.css";

function App() {
  const images = [
    "https://source.unsplash.com/400x300/?hotel",
    "https://source.unsplash.com/400x300/?room",
    "https://source.unsplash.com/400x300/?pool",
    "https://source.unsplash.com/400x300/?resort"
  ];

  const rooms = [
    { name: "Deluxe Room", price: "₹3000/night" },
    { name: "Suite Room", price: "₹5000/night" },
    { name: "Luxury Villa", price: "₹8000/night" }
  ];

  return (
    <div>
      {/* HEADER */}
      <header className="header">
        <h2>Sunset Resort</h2>
        <nav>
          <a href="#">Home</a>
          <a href="#">Rooms</a>
          <a href="#">Contact</a>
        </nav>
      </header>

      {/* HERO */}
      <section className="hero">
        <h1>Welcome to Sunset Resort</h1>
        <p>Luxury stay with nature views</p>
        <button>Book Now</button>
      </section>

      {/* GALLERY */}
      <section>
        <h2>Gallery</h2>
        <div className="grid grid-3">
          {images.map((img, i) => (
            <img key={i} src={img} alt="resort" />
          ))}
        </div>
      </section>

      {/* ROOMS */}
      <section>
        <h2>Our Rooms</h2>
        <div className="grid grid-3">
          {rooms.map((room, i) => (
            <div className="card" key={i}>
              <h3>{room.name}</h3>
              <p>{room.price}</p>
            </div>
          ))}
        </div>
      </section>

      {/* CONTACT */}
      <section>
        <h2>Contact Us</h2>
        <p>📍 Bangalore, India</p>
        <p>📞 9876543210</p>
        <p>📧 info@sunsetresort.com</p>
      </section>

      {/* MAP */}
      <section>
        <h2>Find Us</h2>
        <iframe
          title="map"
          src="https://www.google.com/maps?q=Bangalore&output=embed"
          width="100%"
          height="300"
          style={{ border: 0 }}
        ></iframe>
      </section>

      {/* FOOTER */}
      <footer className="footer">
        <p>© 2026 Sunset Resort</p>
        <p>Follow us on Instagram | Facebook</p>
      </footer>
    </div>
  );
}

export default App;
